bool addComment(char* username, char* content) {
    // Check if the platform has a last viewed post to add a comment to.
    if (globalPlatform.lastViewedPost == NULL) {
        return false; // No last viewed post available
    }

    // Create a new comment using the helper function
    Comment* newComment = createComment(username, content);
    if (newComment == NULL) {
        return false; // Failed to create comment
    }

    // Insert the comment into the post's comment list
    // Assume that comments are stored in a linked list
    if (globalPlatform.lastViewedPost->comments == NULL) {
        globalPlatform.lastViewedPost->comments = newComment; // First comment
    } else {
        // Insert at the end of the comments list
        Comment* current = globalPlatform.lastViewedPost->comments;
        while (current->next != NULL) {
            current = current->next;
        }
        current->next = newComment;
    }

    return true; // Comment successfully added
}

// Create a new comment:
Comment* createComment(char* username, char* content) {
    Comment* newComment = (Comment*)malloc(sizeof(Comment));
    if (newComment == NULL) {
        return NULL; // Failed to allocate memory
    }

    // Set the fields of the new comment
    newComment->username = strdup(username);  // Assumes duplication of string for safe memory allocation
    newComment->content = strdup(content);
    newComment->replies = NULL;
    newComment->next = NULL; // Since this is the last comment in the list for now

    return newComment;
}

// ... other functions and definitions
```

