#include <string.h>

Reply* createReply(char* username, char* content) {
    // Allocate memory for the new reply
    Reply* newReply = (Reply*)malloc(sizeof(Reply));

    // Check for successful memory allocation
    if (newReply == NULL) {
        return NULL;
    }

    // Allocate and copy the username
    newReply->Username = strdup(username);
    if (newReply->Username == NULL) {
        // Clean up and handle the case where strdup fails
