        return NULL;
    }

    // Allocate and copy the content
    newReply->Content = strdup(content);
    if (newReply->Content == NULL) {
        // Clean up and handle the case where strdup fails
        free(newReply->Username);
        free(newReply);
        return NULL;
    }

    // Return the pointer to the new reply
    return newReply;
}
```

